 readonly symbol: string,
 readonly interval: CandleInterval,
 readonly exchangeName: string,
 ) {}
 async waitForInit(initial: boolean) { /* поднять инфраструктуру */ }
 async readCandlesData(limit: number, sinceTimestamp: number) { /* ... */ }
 async writeCandlesData(candles: CandleData[]) { /* ... */ }
}
Записи иммутабельны.
Свеча за конкретную минуту не меняется никогда. Значит, нужен только идемпотентный upsert, который применит только недостающие записи.
Чтение доминирует.
Прогон стратегии — это на 99% чтение: точечные выборки одной свечи по ключу
(биржа, символ, интервал, timestamp)
, много и параллельно.
Нужен строгий контракт видимости
(о нём ниже) — иначе конкурентная запись рассыпается. Мы не хотим сразу скачивать все 525 миллионов записей, нужен lazy loading
Контракт видимости записи
У движка жёсткое требование к долговечности записи: после того как
writeCandlesData
вернул управление, следующий же
readCandlesData
обязан
увидеть записанное. Файловый адаптер выполняет его тривиально (
fs.writeFile
→
fs.readFile
увидят друг друга). А вот наивная реализация поверх любой БД — «прочитай, если нет — вставь» — контракт
нарушает
на конкурентной записи
Оба писателя видят «записи нет», оба вставляют, второй ловит duplicate key, движок уходит в ретрай. Именно то,
как
каждая база закрывает эту гонку без потери контракта, и определяет её место в обзоре.
Попытка 1. MinIO: объектное хранилище, отказ от файлов
Попытка себя не оправдала: MinIO создает по новому отдельному файлу на жестком диске с метаданными для каждого объекта свечи
Базовой реализацией было сохранение файлов на жесткий диск. Это тормозит. Я предположил что можно не менять модель данных вообще: JSON-документ остаётся JSON-документом, просто переезжает с локального диска в S3-совместимое объектное хранилище. Один бакет, ключ объекта — чистая функция контекста:
backtest-kit/candle-items/ccxt_binance/TRXUSDT/1m/1767251220000 → { open, high, low, close, volume, ... }
Детерминированный ключ бесплатно решает контракт долговечности: upsert — это один идемпотентный
PUT
, гонок нет по построению, а S3 гарантирует read-after-write для одиночных объектов. Свечи иммутабельны, поэтому запись —
stat
+
PUT
без скачивания тела:
export class CandleDataService extends BaseMinioStorage("backtest-kit/candle-items") {
 readonly loggerService = inject<LoggerService>(TYPES.loggerService);

 public create = async (dto: ICandleDto): Promise<ICandleRow> => {
 this.loggerService.log("candleDataService create", { dto });
 const key = GET_STORAGE_KEY_FN(dto.symbol, dto.interval, dto.timestamp);
 const now = new Date();
 const row: ICandleRow = {
 id: key,
 exchangeName: EXCHANGE_NAME,
 symbol: dto.symbol,
 interval: dto.interval,
 timestamp: dto.timestamp,
 open: dto.open,
 high: dto.high,
 low: dto.low,
 close: dto.close,
 volume: dto.volume,
 createDate: now,
 updatedDate: now,
 };
S3 хранилища не умеют в диапазонные
запросы по ключам
(нет BETWEEN по timestamp). Для этого, был применен внешний индекс в Redis
export class LogConnectionService extends BaseRedisMap(REDIS_KEY, -1) {
 readonly loggerService = inject<LoggerService>(TYPES.loggerService);

 public register = async (objectName: string): Promise<void> => {
 this.loggerService.log("logConnectionService register", { objectName });
 const redis = await getRedis();
 // One Redis SET per minute: SADD deduplicates repeated names, the floor
 // marker (first-ever minute) bounds the backwards walk in listNewest
 const minute = alignToInterval(new Date(), "1m").getTime();
 await redis
 .pipeline()
 .sadd(GET_MINUTE_KEY_FN(this.connectionKey, minute), objectName)
 .setnx(GET_FLOOR_KEY_FN(this.connectionKey), String(minute))
 .exec();
 };

 public listNewest = async (limit: number, prefix = ""): Promise<string[]> => {
 this.loggerService.log("logConnectionService listNewest", { limit, prefix });
 const redis = await getRedis();
 const floorRaw = await redis.get(GET_FLOOR_KEY_FN(this.connectionKey));
 if (!floorRaw) {
 return [];
 }

 ...
Попытка 2. MongoDB: документная модель без смены схемы
Работать можно, но чтение одной свечи занимает 40мс. Итого: 31 день × 1440 минут в дне × 40 мс за виртуальную минуту ≈ 30 минут. Бизнес процесс ломается так как люди уходят в курилку и возвращаются через час
Я знаю что MongoDB это vendor lock на их облачную базу Atlas, так как в СНГ мало специалистов по ее масштабированию. Но у вендора Mongo Inc есть экосистема: если для Postgres нужно ставить докер образ pgAdmin 4 который вообще веб-сайт
(а у кого-то Mac),
то тут можно просто скачать программу MongoDB Compass
export class CandleDbService extends BaseMongoCRUD(CandleModel) {

 readonly loggerService = inject<LoggerService>(TYPES.loggerService);
 readonly candleCacheService = inject<CandleCacheService>(TYPES.candleCacheService);

 public upsert = async (dto: ICandleDto): Promise<ICandleRow> => {
 this.loggerService.log("candleDbService upsert", { dto });
 const filter = {
 exchangeName: dto.exchangeName,
 symbol: dto.symbol,
 interval: dto.interval,
 timestamp: dto.timestamp,
 };
 const insertOnly = {
 open: dto.open,
 high: dto.high,
 low: dto.low,
 close: dto.close,
 volume: dto.volume,
 };
 const document = await CandleModel.findOneAndUpdate(
 filter,
 { $setOnInsert: insertOnly },
 { upsert: true, new: true, setDefaultsOnInsert: true },
 );
 ...
Чтобы снизить сложность с логарифмической до O(1) можно сделать Redis Lookup, стоит 6гб оперативы, снижает нагрузку на процессор так как нет трафика памяти по шине через пагинацию
export class CandleCacheService extends BaseRedisMap(REDIS_KEY, -1) {
 readonly loggerService = inject<LoggerService>(TYPES.loggerService);

 private _cacheKey(symbol: string, interval: CandleInterval, exchangeName: string, timestamp: number): string {
 return `${exchangeName}:${symbol}:${interval}:${timestamp}`;
 }

 public async getCandleId(symbol: string, interval: CandleInterval, exchangeName: string, timestamp: number): Promise<string | null> {
 this.loggerService.log("candleCacheService getCandleId", { 
 symbol, 
 interval, 
 exchangeName, 
 timestamp,
 });
 const key = this._cacheKey(symbol, interval, exchangeName, timestamp);
 const id = <string>await super.get(key);
 return id ?? null;
 }

 public async setCandleId(row: ICandleRow): Promise<string> {
 this.loggerService.log(`candleCacheService setCandleId`, { 
 symbol: row.symbol, 
 interval: row.interval, 
 timestamp: row.timestamp
 });
 const key = this._cacheKey(row.symbol, row.interval, row.exchangeName, row.timestamp);
 await super.set(key, row.id);
 return row.id;
 }
}
Попытка 3. PostgreSQL + Pgpool-II: финал
В итоге удалось сделать сборку PostgreSQL + Pgpool-II с четырьмя read репликами и одной write. Скорость чтения выросла с 40мс до 10мс, месяц бектеста виртуального времени стоит 7 минут реального. Бизнес процесс не ломается, можно подождать не покидая рабочее место
Ради чего писалась статья — топология кластера.
Нагрузка на 99% состоит из чтения, поэтому перед базой ставится pgpool-II: одна пишущая нода и три читающие реплики. pgpool раскладывает поток точечных
SELECT
по репликам, а весь DML прозрачно маршрутизирует на праймари
По ёмкости одна таблица с такими индексами держит миллиарды строк: 130 млн свечей — это ~260 байт на свечу со всеми индексами, около
34 ГБ
, то есть даже не повод для партиционирования. Максимальная емкость Postgres для одной таблицы это
32 ТБ
export class CandleDbService extends BasePostgresCRUD(CandleModel) {

 readonly loggerService = inject<LoggerService>(TYPES.loggerService);
 readonly candleCacheService = inject<CandleCacheService>(TYPES.candleCacheService);

 public create = async (dto: ICandleDto): Promise<ICandleRow> => {
 this.loggerService.log("candleDbService create", { dto });
 const repo = await super.repo<ICandleRow>();
 const { raw } = await repo
 .createQueryBuilder()
 .insert()
 .values({
 symbol: dto.symbol,
 interval: dto.interval,
 timestamp: dto.timestamp,
 exchangeName: dto.exchangeName,
 open: dto.open,
 high: dto.high,
 low: dto.low,
 close: dto.close,
 volume: dto.volume,
 })
 .orUpdate(["symbol"], ["exchangeName", "symbol", "interval", "timestamp"])
 .returning("*")
 .execute();
 const result = raw[0] as ICandleRow;
 await this.candleCacheService.setCandleId(result);
 return result;
 };
Во всех трёх вариантах перед хранилищем стоит Redis. Популярное объяснение «O(1) вместо O(log n)» на практике
не работает
: обход b-tree на миллиарде строк — это 4–5 страниц, которые давно сидят в кэше, то есть микросекунды. Сетевой раунд-трип на порядок дороже самого обхода. Если бы дело было в асимптотике, кэш можно было бы выбросить.
Пару слов о Redis Lookup
Настоящий выигрыш Redis дает в
снижении трафика памяти на один lookup, то есть в разгрузке CPU базы
. Схема двухходовая: Redis по контекстному ключу отдаёт
id
, база добирает строку по PK — самому дешёвому из возможных обходов; при промахе идём в индекс и заполняем кэш.
Почему это разгружает CPU по каждой базе:
PostgreSQL.
Точечный
SELECT
— это парсер, планировщик, executor, пины буферов, обход 4–5 страниц по 8 КБ со случайными обращениями внутри каждой: десятки промахов L1/L2 и заметная полоса памяти на запрос. Redis
GET
по короткому ключу — это хеш-бакет и короткая строка, одна-две кэш-линии. На то же железо Redis выдаёт 100–200k
GET
/с на ядро против 20–50k точечных
SELECT
/с. Кэш не ускоряет отдельный запрос — он
утраивает-ушестеряет пропускную способность
и оставляет CPU праймари и реплик на реальную работу.
MongoDB.
Паттерн ценнее вдвойне: промах по составному индексу тянет за собой декомпрессию блока WiredTiger — чистый CPU, помноженный на полосу памяти. Redis-кэш
ctx → _id
превращает горячий путь в
GET
+
findById
, снимая и декомпрессию, и обход индекса.
MinIO.
Здесь per-object кэш не нужен: детерминированный ключ и есть «O(1)-адресация». Redis работает иначе — минутный индекс подменяет S3
LIST
(который на сервере читает метакаталоги с диска), а дедуп-набор записанных ключей убирает лавину
stat
-запросов.
Спасибо за внимание!

description:
Аннотации легко воспринимать как декоративную часть языка. Поставили
@Deprecated
, добавили
@Suppress
, пометили DTO через
@JsonClass
- и пошли дальше. Но в большом Android-проекте аннотации быстро пе...

full_text:
Аннотации легко воспринимать как декоративную часть языка. Поставили
@Deprecated
, добавили
@Suppress
, пометили DTO через
@JsonClass
- и пошли дальше. Но в большом Android-проекте аннотации быстро перестают быть просто подсказками для IDE. Они становятся контрактом между кодом и инструментами: компилятором, статическим анализатором, генератором кода, DI-фреймворком, сериализатором или внутренней платформенной инфраструктурой.
В этой статье разберем, что на самом деле происходит вокруг аннотаций в Kotlin, чем отличаются
SOURCE
,
BINARY
и
RUNTIME
, почему
@Composable
- это не просто красивая метка, чем kapt отличается от KSP, и на каких практических задачах annotation processing может быть полезен в Android-разработке.
Аннотация - это метаданные для кода
Самый простой пример:
@Deprecated("Use deliveryType instead")
val isManualPickup: Boolean
На первый взгляд это просто сообщение для разработчика. Но уже здесь есть несколько важных деталей:
аннотация добавляет к элементу кода метаданные;
эти метаданные может прочитать не только человек, но и инструмент;
инструмент может принять решение: подсветить warning, сгенерировать код, запретить использование, изменить поведение сборки.
Аннотации встречаются почти везде:
@JsonClass(generateAdapter = true)
data class CreateChatRequest(
 @Json(name = "chat")
 val params: CreateChatParams,
)

@Volatile
private var constructorRef: Constructor<CreateChatParams>? = null

@POST("user/reviews/")
suspend fun postFeedback(
 @Body request: PostFeedbackRequest,
): PostFeedbackResponse

@Suppress("CyclomaticComplexMethod")
override fun checkResponse(response: Response): ProjectException?
Каждая из них решает свою задачу.
@JsonClass
включает генерацию адаптера, Retrofit-аннотации описывают HTTP-контракт,
@Suppress
влияет на статический анализ,
@Volatile
меняет семантику доступа к полю на JVM.
То есть аннотация сама по себе почти ничего не делает. Смысл появляется там, где есть инструмент, который умеет ее прочитать.
![Аннотация как контракт с инструментами]n(
https://habrastorage.org/webt/cd/e6/42/cde642aa079f79cf58a1ded94c243db4.png
)
Аннотации тоже аннотируются
У аннотаций есть собственные аннотации. Например,
@Deprecated
в Kotlin объявлен примерно так:
@Target(
 AnnotationTarget.CLASS,
 AnnotationTarget.FUNCTION,
 AnnotationTarget.PROPERTY,
 AnnotationTarget.CONSTRUCTOR,
 AnnotationTarget.TYPEALIAS,
)
@MustBeDocumented
public annotation class Deprecated(
 val message: String,
 val replaceWith: ReplaceWith = ReplaceWith(""),
 val level: DeprecationLevel = DeprecationLevel.WARNING,
)
@Target
определяет, к каким элементам можно применить аннотацию: к классу, функции, свойству, параметру, другой аннотации и так далее.
@MustBeDocumented
говорит инструментам документации, что эту аннотацию стоит показывать в сгенерированной документации.
Есть забавная рекурсивная деталь:
@Target
сам является аннотацией, которая применяется к аннотациям:
@Target(AnnotationTarget.ANNOTATION_CLASS)
@MustBeDocumented
public annotation class Target(
 vararg val allowedTargets: AnnotationTarget,
)
Это хороший пример того, что система аннотаций не является плоской. Она задает маленький язык поверх языка программирования.
Retention: где живет аннотация
Одна из самых важных мета-аннотаций -
@Retention
. Она определяет, на каком этапе жизненного цикла кода аннотация будет доступна.
В Kotlin есть три варианта:
public enum class AnnotationRetention {
 SOURCE,
 BINARY,
 RUNTIME,
}
SOURCE
Аннотация доступна только на этапе компиляции и не попадает в бинарный результат.
Это хороший выбор для:
генерации кода;
статического анализа;
compile-time проверок;
внутренних маркеров, которые не нужны в рантайме.
Пример:
@Target(AnnotationTarget.CLASS)
@Retention(AnnotationRetention.SOURCE)
annotation class GenerateFactory
Если аннотацию читает KSP-процессор и после сборки она больше не нужна,
SOURCE
обычно достаточно.
BINARY
Аннотация сохраняется в скомпилированных class-файлах, но не видна через reflection в рантайме.
Это полезно, когда метаданные нужны инструментам, работающим с байткодом, но не нужны приложению во время выполнения. Типичный Android-пример - аннотации, которые учитываются при минификации, обфускации или анализе байткода.
@Keep
sealed class AppLanguage(
 val name: String,
 val locale: String,
 val icon: Int,
)
RUNTIME
Аннотация попадает в бинарный результат и доступна во время выполнения через reflection.
@Target(AnnotationTarget.CLASS)
@Retention(AnnotationRetention.RUNTIME)
annotation class ScreenName(val value: String)

@ScreenName("checkout")
class CheckoutScreen

val annotation = CheckoutScreen::class
 .annotations
 .filterIsInstance<ScreenName>()
 .firstOrNull()
RUNTIME
нужен для сценариев, где решение действительно принимается во время выполнения: reflection-based DI, сериализация, runtime discovery, тестовые фреймворки.
Но за удобство приходится платить. Reflection сложнее валидировать на этапе компиляции, его легче сломать переименованием или обфускацией, а ошибки часто приезжают позже, чем хотелось бы.
Правило простое: выбирайте минимальный retention, который решает задачу. Если аннотация нужна только процессору, не стоит тащить ее в runtime.
Retention: где живет аннотация
Где здесь метапрограммирование
Метапрограммирование - это когда программа работает с другой программой как с данными: читает ее структуру, анализирует, генерирует новый код или меняет поведение.
Аннотации удобны именно как маркеры для такого процесса.
Как выбрать механизм метапрограммирования
Например, мы можем явно сказать инструменту:
@GenerateAdapter
data class UserDto(
 val id: String,
 val name: String,
)
А дальше уже не писать руками однотипный adapter/factory/registry. Процессор найдет класс, проверит его контракт и создаст дополнительный код.
Важно разделять два уровня:
annotation processing обычно читает код и генерирует новые файлы;
compiler plugin может глубже интегрироваться в компиляцию и менять семантику или форму кода.
KSP относится к первому уровню. Он не должен модифицировать исходники и не видит тела функций как полноценное дерево выражений. А вот Compose Compiler - это уже пример полноценного compiler plugin.
Где в сборке живут KSP, kapt и compiler plugins
@Composable как пример compiler plugin
@Composable
выглядит как обычная аннотация:
@Composable
fun Counter() {
 val count = remember { mutableStateOf(1) }

 Button(
 onClick = { count.value += 1 },
 ) {
 Text("Count: ${count.value}")
 }
}
Но за ней стоит compiler plugin, который трансформирует код. Упрощенно можно представить, что компилятор добавляет служебный
Composer
, ключи, группы, проверки изменений и все, что нужно runtime для рекомпозиции.
То есть
@Composable
не просто “помечает функцию для красоты”. Она включает другой режим компиляции функции и вводит правила:
composable-функции можно вызывать только из composable-контекста;
compiler plugin может строить модель для рекомпозиции;
часть ошибок можно поймать еще на этапе компиляции.
Поэтому
@Composable
часто сравнивают с
suspend
: обе конструкции меняют способ вызова функции. Разница в том, что
suspend
стал частью языка, а
@Composable
реализован через библиотеку и compiler plugin.
С Kotlin 2.0 Compose Compiler переехал в Kotlin repository и получил Gradle plugin с версией, совпадающей с Kotlin. Это хороший пример того, как близко такие инструменты живут к компилятору.
Annotation processing: зачем он нужен
Annotation processing обычно нужен по трем причинам.
Первая - перенести работу из runtime в compile time. Лучше узнать об ошибке на сборке, чем получить crash в пользовательской сессии.
Вторая - избавиться от reflection там, где это возможно. Reflection мощная, но хрупкая: она хуже дружит с обфускацией, сложнее покрывается compile-time проверками и часто прячет ошибки до момента выполнения.
Третья - убрать шаблонный код. Именно это сделали популярные библиотеки вроде Room, Dagger, Moshi и многих других: разработчик описывает контракт, а скучную часть пишет генератор.
Упрощенный flow выглядит так:
Компилятор запускает процессор.
Процессор сканирует исходники и ищет нужные аннотации или символы.
Процессор валидирует контракт.
Процессор генерирует новые файлы.
Компилятор компилирует исходный и сгенерированный код вместе.
Если сгенерированный код сам добавил новые символы, возможен следующий раунд обработки.
Annotation processing: раунды обработки
Раунды важны. Иногда один процессор генерирует код, который должен быть увиден другим процессором или следующим проходом того же процессора. На этом месте часто появляются неожиданные проблемы с порядком, incremental build и кешированием.
kapt и KSP
Исторически в Kotlin долго использовали kapt. Он позволяет запускать Java annotation processors на Kotlin-коде.
Цена этого подхода - Java stubs. kapt генерирует stub-файлы из Kotlin source code, а потом Java-процессоры работают уже с ними. Это дает совместимость с большой Java-экосистемой, но добавляет отдельный этап в сборку.
KSP - Kotlin-first альтернатива. Он анализирует Kotlin-код напрямую и предоставляет API на уровне символов: файлы, классы, функции, свойства, параметры, типы, generics, visibility modifiers и так далее.
kapt vs KSP: два пути к generated code
Коротко:
Вопрос
kapt
